INSERT INTO public.agents (name, slug, description, long_description, category, icon_url, is_published, base_credit_cost, config_schema, required_credentials, rating, total_deployments, version, use_cases)
VALUES
('Email Auto-Responder', 'email-auto-responder', 'Automatically draft and send email replies based on your rules and AI-generated responses.', 'A powerful email assistant that reads incoming emails and drafts contextual replies matching your preferred tone, length, and business rules. Perfect for handling routine correspondence, support emails, and follow-ups.', 'Email', 'mail', true, 3, '{"fields":[{"name":"tone","type":"select","options":["Professional","Friendly","Formal","Casual","Empathetic","Assertive"],"default":"Professional"},{"name":"response_length","type":"select","options":["Brief (2-3 sentences)","Medium (1 paragraph)","Detailed (2-3 paragraphs)"],"default":"Medium (1 paragraph)"},{"name":"rules","type":"text","default":"Be polite, address all points raised, sign off with best regards"},{"name":"email_content","type":"text","default":""}]}', '{}', 4.8, 245, '1.0', ARRAY['Auto-reply to routine customer emails', 'Draft responses matching your brand voice', 'Handle support inquiries while you sleep']),
('Lead Scraper Pro', 'lead-scraper-pro', 'Find and qualify leads from websites, LinkedIn, and directories automatically.', 'An intelligent lead generation agent that researches companies matching your ideal customer profile. Generates detailed prospect lists with company info, estimated size, industry details, and personalized outreach angles.', 'Sales', 'search', true, 10, '{"fields":[{"name":"industry","type":"text","default":"Technology"},{"name":"company_size","type":"select","options":["1-10","11-50","51-200","201-1000","1000+"],"default":"11-50"},{"name":"location","type":"text","default":"United States"},{"name":"num_leads","type":"select","options":["5","10","20"],"default":"10"}]}', '{}', 4.6, 189, '1.0', ARRAY['Build targeted prospect lists by industry', 'Find decision-maker contact info', 'Research companies matching your ICP']),
('Blog Writer', 'blog-writer', 'Generate SEO-optimized blog posts from topics or keywords in minutes.', 'A professional content writer that creates well-structured, engaging blog posts optimized for search engines. Supports multiple tones, target audiences, and word counts with proper heading hierarchy and call-to-actions.', 'Content', 'pen-tool', true, 2, '{"fields":[{"name":"topic","type":"text","default":""},{"name":"tone","type":"select","options":["Informative","Conversational","Persuasive","Technical"],"default":"Informative"},{"name":"word_count","type":"select","options":["500","1000","1500","2000"],"default":"1000"},{"name":"target_audience","type":"text","default":"General audience"}]}', '{}', 4.9, 312, '1.0', ARRAY['Generate blog posts from topic ideas', 'Create SEO-optimized content at scale', 'Repurpose content across formats']),
('Data Extractor', 'data-extractor', 'Convert PDFs, CSVs, and documents into structured data instantly.', 'A data extraction specialist that parses unstructured text from any document format and outputs clean, structured data in JSON, CSV, or table format. Handles invoices, receipts, reports, and more.', 'Data', 'database', true, 5, '{"fields":[{"name":"input_text","type":"text","default":""},{"name":"output_format","type":"select","options":["JSON","CSV","Table","Summary"],"default":"JSON"}]}', '{}', 4.7, 178, '1.0', ARRAY['Extract data from PDFs and documents', 'Convert unstructured text to JSON/CSV', 'Parse invoices and receipts']),
('Customer Support Bot', 'support-bot', 'Answer customer questions from your knowledge base 24/7 with AI.', 'An always-on support agent that answers customer inquiries based on your knowledge base documents. Maintains a friendly tone, knows when to escalate, and provides consistent answers across all interactions.', 'Support', 'headphones', true, 4, '{"fields":[{"name":"knowledge_base","type":"text","default":""},{"name":"tone","type":"select","options":["Professional","Friendly","Technical"],"default":"Friendly"},{"name":"question","type":"text","default":""}]}', '{}', 4.7, 156, '1.0', ARRAY['Answer FAQs 24/7 from your knowledge base', 'Reduce support ticket volume', 'Provide consistent responses']),
('Social Media Scheduler', 'social-media-scheduler', 'Create and schedule engaging posts across all platforms.', 'A social media strategist that generates platform-optimized posts with hashtags, emojis, and posting time recommendations. Supports Twitter, LinkedIn, Instagram, and multi-platform campaigns.', 'Social Media', 'share-2', true, 4, '{"fields":[{"name":"platforms","type":"select","options":["Twitter","LinkedIn","Instagram","All"],"default":"All"},{"name":"tone","type":"select","options":["Professional","Casual","Humorous","Inspirational"],"default":"Professional"},{"name":"topic","type":"text","default":""},{"name":"num_posts","type":"select","options":["3","5","7"],"default":"5"}]}', '{}', 4.5, 134, '1.0', ARRAY['Plan and schedule posts across platforms', 'Generate captions with hashtags', 'Maintain consistent posting']),
('Competitor Monitor', 'competitor-monitor', 'Track competitor pricing, features, and updates automatically.', 'A competitive intelligence agent that analyzes competitors across pricing, features, marketing, and market positioning. Delivers actionable insights and recommendations for differentiation.', 'Marketing', 'eye', true, 12, '{"fields":[{"name":"competitor_url","type":"text","default":""},{"name":"focus_areas","type":"select","options":["Pricing","Features","Marketing","All"],"default":"All"},{"name":"industry","type":"text","default":""}]}', '{}', 4.6, 98, '1.0', ARRAY['Track competitor pricing changes', 'Monitor feature launches', 'Get weekly intelligence reports']),
('Code Reviewer', 'code-reviewer', 'Review pull requests and suggest improvements with AI analysis.', 'A senior-level code reviewer that analyzes code for security vulnerabilities, performance issues, and quality improvements. Provides actionable feedback with refactored code examples and a quality score.', 'Development', 'file-text', true, 15, '{"fields":[{"name":"language","type":"select","options":["JavaScript","TypeScript","Python","Go","Rust"],"default":"TypeScript"},{"name":"focus","type":"select","options":["Security","Performance","Code Quality","All"],"default":"All"},{"name":"code","type":"text","default":""}]}', '{}', 4.8, 87, '1.0', ARRAY['Review PRs for security issues', 'Catch performance anti-patterns', 'Enforce code style']),
('Invoice Processor', 'invoice-processor', 'Extract data from invoices and organize in spreadsheets automatically.', 'An accounts payable specialist that extracts line items, totals, dates, and vendor info from invoice documents. Outputs structured data ready for import into accounting systems.', 'Data', 'bar-chart-2', true, 6, '{"fields":[{"name":"input_text","type":"text","default":""},{"name":"output_format","type":"select","options":["Spreadsheet","JSON","CSV"],"default":"JSON"},{"name":"fields_to_extract","type":"text","default":"invoice_number, date, amount, vendor"}]}', '{}', 4.4, 67, '1.0', ARRAY['Extract line items from invoices', 'Organize data into spreadsheets', 'Flag duplicate invoices']),
('Meeting Summarizer', 'meeting-summarizer', 'Transcribe meetings, generate summaries, and extract action items.', 'A meeting notes specialist that transforms raw transcripts into structured summaries with executive overview, key decisions, action items with assignees, and follow-up questions.', 'Content', 'mic', true, 8, '{"fields":[{"name":"transcript","type":"text","default":""},{"name":"output_type","type":"select","options":["Summary","Action Items","Full Notes","All"],"default":"All"}]}', '{}', 4.8, 203, '1.0', ARRAY['Generate meeting summaries', 'Extract key decisions', 'Share concise notes with team'])
